class Solution:
    def minimumJumps(self, forbidden, a, b, x):
        from collections import deque
        blocked = set(forbidden)
        if 0 in blocked:
            return -1
        if x == 0:
            return 0
        limit = max([x] + list(forbidden)) + a + b + 1
        seen_fwd = [False] * (limit + 1)
        seen_back = [False] * (limit + 1)
        seen_fwd[0] = True
        queue = deque([(0, 0, True)])
        while queue:
            pos, steps, can_back = queue.popleft()
            moves = [(pos + a, True)]
            if can_back:
                moves.append((pos - b, False))
            for nxt, nxt_can_back in moves:
                if 0 <= nxt <= limit and nxt not in blocked:
                    if nxt == x:
                        return steps + 1
                    marker = seen_fwd if nxt_can_back else seen_back
                    if not marker[nxt]:
                        marker[nxt] = True
                        queue.append((nxt, steps + 1, nxt_can_back))
        return -1

