        visited = {(0, True)}
        queue = deque([(0, True, 0)])
        while queue:
            pos, can_back, steps = queue.popleft()
            if pos == x:
                return steps
            forward = pos + a
            if 0 <= forward <= limit and forward not in blocked and (forward, True) not in visited:
                visited.add((forward, True))
                queue.append((forward, True, steps + 1))
            if can_back:
                backward = pos - b
                if 0 <= backward <= limit and backward not in blocked and (backward, False) not in visited:
                    visited.add((backward, False))
                    queue.append((backward, False, steps + 1))
        return -1

