var minimumJumps = function(forbidden, a, b, x) {
    const blocked = new Set(forbidden);
    if (blocked.has(0)) return -1;
    const limit = Math.max(x, ...forbidden) + a + b;
    const visitedFwd = new Set([0]);
    const visitedBack = new Set();
    const queue = [[0, true, 0]];
    let head = 0;
    while (head < queue.length) {
        const [pos, canBack, steps] = queue[head++];
        if (pos === x) return steps;
        const fwd = pos + a;
        if (fwd >= 0 && fwd <= limit && !blocked.has(fwd) && !visitedFwd.has(fwd)) {
            visitedFwd.add(fwd);
            queue.push([fwd, true, steps + 1]);
        }
        if (canBack) {
            const bwd = pos - b;
            if (bwd >= 0 && bwd <= limit && !blocked.has(bwd) && !visitedBack.has(bwd)) {
                visitedBack.add(bwd);
                queue.push([bwd, false, steps + 1]);
            }
        }
    }
    return -1;
};
